// ── Extraire infos du fichier uploadé ──────────────────────────
const item = items[0];
const binaryKeys = Object.keys(item.binary || {});
if (binaryKeys.length === 0) {
  throw new Error('Aucun fichier trouvé dans le formulaire');
}
const binaryKey = binaryKeys[0];
const binaryMeta = item.binary[binaryKey];
const fileName = binaryMeta.fileName || binaryMeta.id || binaryKey;
const fileExtension = fileName.split('.').pop().toLowerCase().replace(/[^a-z0-9]/g, '');

return [{
  json: {
    ...item.json,
    _binaryKey: binaryKey,
    _fileName: fileName,
    _fileExtension: fileExtension,
    _mimeType: binaryMeta.mimeType || ''
  },
  binary: item.binary
}];

const item = items[0];
const binaryKey = item.json._binaryKey || Object.keys(item.binary || {})[0];
const binaryMeta = item.binary[binaryKey];

// Laisser l'erreur remonter sans try/catch pour voir le vrai problème
const buf = await this.helpers.getBinaryDataBuffer(item, binaryKey);
const html = buf.toString('utf-8');

const MARKER = 'const initialRecords = ';
if (!html.includes(MARKER)) {
  throw new Error(
    'getBinaryDataBuffer OK mais MARKER absent. ' +
    'html.length=' + html.length + ' ' +
    'debut=' + JSON.stringify(html.substring(0, 100))
  );
}

const MARKER_END = ';\nlet currentRecords = [];';
const si = html.indexOf(MARKER);
const ei = html.indexOf(MARKER_END, si + MARKER.length);
if (ei === -1) throw new Error('Fin de initialRecords non trouvée.');

const rawRecords = JSON.parse(html.substring(si + MARKER.length, ei));
if (!Array.isArray(rawRecords) || !rawRecords.length) throw new Error('initialRecords vide.');

const MOIS_FR = {
  'janvier':1,'fevrier':2,'février':2,'mars':3,'avril':4,'mai':5,'juin':6,
  'juillet':7,'aout':8,'août':8,'septembre':9,'octobre':10,'novembre':11,
  'decembre':12,'décembre':12
};
function parseJour(jour, year) {
  const j = String(jour||'').trim();
  const m1 = j.match(/^(\d{1,2})\/(\d{1,2})$/);
  if (m1) return year+'-'+String(+m1[2]).padStart(2,'0')+'-'+String(+m1[1]).padStart(2,'0');
  const m2 = j.match(/^(\d{1,2})[-\s](.+)$/);
  if (m2) {
    const mNum = MOIS_FR[m2[2].trim().toLowerCase()];
    if (mNum) return year+'-'+String(mNum).padStart(2,'0')+'-'+String(+m2[1]).padStart(2,'0');
  }
  return null;
}

const groups = {};
for (const r of rawRecords) {
  const ym = String(r.kw_y||'').match(/(\d{4})$/);
  const year = ym ? ym[1] : String(new Date().getFullYear());
  const reportDate = parseJour(r.jour, year);
  if (!reportDate) continue;
  const plant  = String(r.plant||'BMW U11').trim();
  const groupe = String(r.groupe||'').trim();
  const key    = reportDate+'||'+plant+'||'+groupe;
  if (!groups[key]) groups[key] = {
    report_date:reportDate, plant, group_name:groupe,
    process:String(r.psm||'').trim(), circuit:String(r.segment||'').trim(),
    perimeter:plant, actif:0,present:0,p:0,np:0,sq:0,ac:0,rv:0,ml:0,
    heures_presence:0,heures_sup:0,retard:0,_rows:0
  };
  const g=groups[key];
  g.actif+=+(r.actif||0); g.present+=+(r.present||0);
  g.p+=+(r.p||0); g.np+=+(r.np||0); g.sq+=+(r.sq||0);
  g.ac+=+(r.ac||0); g.rv+=+(r.rv||0); g.ml+=+(r.ml||0);
  g.heures_presence+=+(r.presence_hours||0);
  g.heures_sup+=+(r.h_sup||0); g.retard+=+(r.retard||0);
  g._rows++;
}

const uploadedBy = item.json['Uploaded by']||'';
const fileName   = item.json._fileName||'';
const out = Object.values(groups).map(g => {
  const ml=g.ml,md=0,p=g.p,np=g.np,actif=g.actif,present=g.present;
  const r2=v=>parseFloat(v.toFixed(2));
  return { json:{
    _parseSource:'html_initialRecords',
    report_date:g.report_date, plant:g.plant,
    process:g.process, circuit:g.circuit, group_name:g.group_name, perimeter:g.perimeter,
    actif,present,nb_abs:actif-present,p,np,sq:g.sq,ac:g.ac,rv:g.rv,
    ml,md,maladie:ml,mise_en_demeure:md,
    abs_p_rate:   actif>0?r2(p/actif*100):0,
    abs_np_rate:  actif>0?r2(np/actif*100):0,
    total_abs:p+np,
    taux_presence:actif>0?r2(present/actif*100):0,
    heures_presence:r2(g.heures_presence),retard:r2(g.retard),
    heures_sup:r2(g.heures_sup),soll:0,ist:0,delta:0,
    raw_json:JSON.stringify({source:'html_initialRecords',rows:g._rows}),
    uploaded_by:uploadedBy,source_file:fileName
  }};
});
if (!out.length) throw new Error('Aucune ligne après agrégation.');
out[0].json._meta = JSON.stringify({parseSource:'html_initialRecords',rowCount:out.length,uploadedBy,fileName});
return out;

const item = items[0];
const binaryKey = item.json._binaryKey || Object.keys(item.binary || {})[0];

if (!binaryKey || !item.binary || !item.binary[binaryKey]) {
  throw new Error('Aucun fichier CSV trouvé');
}

const binaryMeta = item.binary[binaryKey];
const reportDate = item.json['Date du rapport'];
const plant = item.json['Plant'] || 'BMW U11';
const uploadedBy = item.json['Uploaded by'] || '';
const fileName = item.json._fileName || '';

let csv;
try {
  if (binaryMeta.data) {
    csv = Buffer.from(binaryMeta.data, 'base64').toString('utf-8');
  } else {
    const buf = await this.helpers.getBinaryDataBuffer(item, binaryKey);
    csv = buf.toString('utf-8');
  }
} catch(e) {
  throw new Error('Impossible de lire le fichier CSV: ' + e.message);
}

function detectDelim(s) {
  const c={';':(s.match(/;/g)||[]).length,',':(s.match(/,/g)||[]).length,'\t':(s.match(/\t/g)||[]).length,'|':(s.match(/\|/g)||[]).length};
  return Object.entries(c).sort((a,b)=>b[1]-a[1])[0][0];
}
function parseLine(l, d) {
  const r=[]; let cur='',inQ=false;
  for (const ch of l) { if(ch==='"'){inQ=!inQ;}else if(ch===d&&!inQ){r.push(cur.trim());cur='';}else{cur+=ch;} }
  r.push(cur.trim()); return r;
}

const lines = csv.replace(/\r\n/g,'\n').replace(/\r/g,'\n').split('\n').filter(l=>l.trim());
if (lines.length < 2) throw new Error('Fichier CSV vide');

const delim = detectDelim(lines.slice(0,5).join('\n'));
const headers = parseLine(lines[0], delim);
const rows = [];
for (let i=1; i<lines.length; i++) {
  const cells = parseLine(lines[i], delim);
  if (cells.every(c=>c==='')) continue;
  const obj={}; headers.forEach((h,idx)=>{obj[h]=cells[idx]??'';}); rows.push(obj);
}

if (!rows.length) throw new Error('CSV sans données');
const src = 'csv:' + (delim==='\t'?'tab':delim);
return rows.map(r => ({
  json: { ...r, _reportDate: reportDate, _plant: plant, _uploadedBy: uploadedBy, _fileName: fileName, _parseSource: src }
}));

// ── Normaliser colonnes + appliquer règles métier ──────────────────────────
// REGLE CRITIQUE : maladie = ML SEULEMENT (jamais ML+MD)

const COLUMN_MAP = {
  'date':'report_date','date du rapport':'report_date','jour':'report_date',
  'report_date':'report_date',
  'plant':'plant','usine':'plant','site':'plant',
  'perimetre':'perimeter','perimeter':'perimeter','per':'perimeter',
  'process':'process','processus':'process','proc':'process',
  'circuit':'circuit','circ':'circuit',
  'groupe':'group_name','group':'group_name','grp':'group_name',
  'group name':'group_name','group_name':'group_name',
  'area':'area','zone':'area','secteur':'area',
  'actif':'actif','actif hc':'actif','active':'actif','hc':'actif',
  'headcount':'actif','total actif':'actif',
  'present':'present','presents':'present','nb presents':'present',
  'nb abs':'nb_abs','nb_abs':'nb_abs','nombre absence':'nb_abs','absences':'nb_abs',
  'p':'p','abs p':'p','abs planifiee':'p','planifiee':'p','planned':'p',
  'np':'np','abs np':'np','abs non planifiee':'np','non planifiee':'np','unplanned':'np',
  'sq':'sq','sans questionnaire':'sq',
  'ac':'ac','absence continue':'ac','abs continue':'ac',
  'rv':'rv','rendez-vous':'rv','rdv':'rv',
  'ml':'ml','maladie':'ml',
  'md':'md','mise en demeure':'md','mise-en-demeure':'md',
  '%abs p':'abs_p_rate','taux abs p':'abs_p_rate','abs_p_rate':'abs_p_rate',
  '%abs np':'abs_np_rate','taux abs np':'abs_np_rate','abs_np_rate':'abs_np_rate',
  'total abs':'total_abs','total absence':'total_abs','total_abs':'total_abs',
  'taux presence':'taux_presence','taux présence':'taux_presence','taux_presence':'taux_presence',
  'heures presence':'heures_presence','heures_presence':'heures_presence',
  'h presence':'heures_presence',
  'retard':'retard','retards':'retard',
  'h sup':'heures_sup','heures sup':'heures_sup','heures_sup':'heures_sup','hsup':'heures_sup',
  'soll':'soll','ist':'ist','actuel':'ist',
  'delta':'delta','ecart':'delta',
};

const NUMERIC_COLS = new Set([
  'actif','present','nb_abs','p','np','sq','ac','rv','ml','md',
  'abs_p_rate','abs_np_rate','total_abs','taux_presence','heures_presence',
  'retard','heures_sup','soll','ist','delta'
]);

function normalizeKey(key) {
  return String(key).toLowerCase()
    .replace(/[éèêë]/g,'e').replace(/[àâä]/g,'a').replace(/[ùûü]/g,'u')
    .replace(/[îï]/g,'i').replace(/[ôö]/g,'o').replace(/ç/g,'c')
    .trim().replace(/\s+/g,' ');
}

function toNum(v) {
  if (v===null||v===undefined||v==='') return 0;
  const n = parseFloat(String(v).replace(',','.').replace(/[^0-9.\-]/g,''));
  return isNaN(n)?0:n;
}

const allItems = $input.all();
if (!allItems.length) throw new Error('Aucune donnée reçue pour normalisation');

const firstItem = allItems[0];
// Méta globale (formulaire) — utilisée seulement pour CSV/Excel
const globalReportDate = firstItem.json._reportDate || firstItem.json['Date du rapport'];
const globalPlant      = firstItem.json._plant      || firstItem.json['Plant'] || 'BMW U11';
const uploadedBy       = firstItem.json._uploadedBy || firstItem.json['Uploaded by'] || '';
const fileName         = firstItem.json._fileName   || '';
const parseSource      = firstItem.json._parseSource || 'unknown';

// ── Détection HTML pré-normalisé ────────────────────────────────────────────
const isHtml = parseSource === 'html_initialRecords';

const normalizedItems = allItems.map(item => {
  const raw = item.json;

  if (isHtml) {
    // Données déjà agrégées et normalisées par le Parser HTML
    // Appliquer uniquement les règles ML/MD et recalculer si nécessaire
    const ml = toNum(raw.ml);
    const md = toNum(raw.md);
    const actif   = toNum(raw.actif);
    const present = toNum(raw.present);
    const p       = toNum(raw.p);
    const np      = toNum(raw.np);
    return { json: {
      ...raw,
      ml, md,
      maladie:          ml,   // REGLE CRITIQUE
      mise_en_demeure:  md,
      nb_abs:    raw.nb_abs    ?? (actif - present),
      total_abs: raw.total_abs ?? (p + np),
      abs_p_rate:    raw.abs_p_rate    ?? (actif > 0 ? Math.round(p  /actif*10000)/100 : 0),
      abs_np_rate:   raw.abs_np_rate   ?? (actif > 0 ? Math.round(np /actif*10000)/100 : 0),
      taux_presence: raw.taux_presence ?? (actif > 0 ? Math.round(present/actif*10000)/100 : 0),
      delta: raw.delta ?? (toNum(raw.ist) - toNum(raw.soll)),
      raw_json: raw.raw_json || JSON.stringify(raw),
    }};
  }

  // ── Normalisation standard (CSV / Excel) ──────────────────────────────────
  const norm = {};
  for (const [key, val] of Object.entries(raw)) {
    if (key.startsWith('_')) continue;
    const mapped = COLUMN_MAP[normalizeKey(key)];
    if (mapped) norm[mapped] = val;
  }

  for (const col of NUMERIC_COLS) norm[col] = toNum(norm[col]);

  const ml  = toNum(norm.ml);
  const md  = toNum(norm.md);
  // REGLE CRITIQUE : maladie = ML SEULEMENT (JAMAIS ml + md)
  norm.maladie         = ml;
  norm.mise_en_demeure = md;

  const actif = norm.actif || 0;
  const p     = norm.p     || 0;
  const np    = norm.np    || 0;

  if (!norm.total_abs)      norm.total_abs    = p + np;
  if (!norm.abs_p_rate   && actif>0) norm.abs_p_rate   = Math.round(p/actif*10000)/100;
  if (!norm.abs_np_rate  && actif>0) norm.abs_np_rate  = Math.round(np/actif*10000)/100;
  if (!norm.taux_presence && actif>0) norm.taux_presence = Math.round(toNum(norm.present)/actif*10000)/100;
  if (!norm.delta) norm.delta = toNum(norm.ist) - toNum(norm.soll);

  norm.report_date  = globalReportDate;
  norm.plant        = globalPlant;
  norm.uploaded_by  = uploadedBy;
  norm.source_file  = fileName;
  norm.raw_json     = JSON.stringify(raw);

  return { json: norm };
});

// Métadonnées résumé sur le premier item
normalizedItems[0].json._meta = JSON.stringify({
  reportDate: globalReportDate || normalizedItems[0].json.report_date,
  plant:      globalPlant      || normalizedItems[0].json.plant,
  uploadedBy, fileName, parseSource,
  rowCount: normalizedItems.length
});

return normalizedItems;

// ── Préparer les lignes pour insertion Neon PostgreSQL ─────────
const allItems = $input.all();
const COLS = [
  'report_date','plant','perimeter','process','circuit','group_name','area',
  'actif','present','nb_abs','p','np','sq','ac','rv','ml','md',
  'maladie','mise_en_demeure','abs_p_rate','abs_np_rate','total_abs',
  'taux_presence','heures_presence','retard','heures_sup','soll','ist','delta',
  'raw_json','source_file','uploaded_by'
];

return allItems.map(item => {
  const row = {};
  for (const col of COLS) {
    row[col] = item.json[col] ?? null;
  }
  // Extraire meta du premier item
  if (item.json._meta) row._meta = item.json._meta;
  return { json: row };
});
